<?php declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/auth.php';require_once dirname(__DIR__,2).'/includes/conexion.php';exigirRol(['usuario']);$sid=substr((string)($_GET['session_id']??''),0,255);$q=obtenerConexion()->prepare('SELECT numero,total,moneda,estado FROM pedidos WHERE stripe_checkout_session_id=:s AND usuario_id=:u');$q->execute(['s'=>$sid,'u'=>$_SESSION['usuario_id']]);$p=$q->fetch();$pageTitle='Estado del pedido | Atenea';$activePage='productos';require dirname(__DIR__,2).'/includes/header.php';?><main class="main"><section class="section"><div class="container text-center"><?php if($p):?><h1>Gracias por tu compra</h1><p>Pedido <?=atenea_e($p['numero'])?> · $<?=number_format((float)$p['total'],2)?> <?=strtoupper($p['moneda'])?></p><div class="alert alert-info">Estado actual: <?=atenea_e($p['estado'])?>. La confirmación definitiva depende del webhook de Stripe.</div><a class="btn-atenea" href="<?=atenea_url('src/estudiantes/pedidos.php')?>">Ver mis pedidos</a><?php else:?><h1>Pedido no encontrado</h1><?php endif;?></div></section></main><?php require dirname(__DIR__,2).'/includes/footer.php';?>
